solutions.cpp:
class Solution {
public:
int numExchanges(vector<int>& coins, int amount) {
vector<int> dp(amount + 1, 0);
for (int i = 0; i < coins.size(); i++) {
for (int j = coins[i]; j <= amount; j++) {
if (dp[j - coins[i]] != 0) {
if (dp[j] < dp[j - coins[i]] + 1) {
dp[j] = dp[j - coins[i]] + 1;
}
}
}
}
return dp[amount];
}
};
